import React, { useState, useMemo } from 'react';
import { AppState, Employee, AttendanceRecord } from '../types';
import { Users, UserPlus, X, ChevronRight, ChevronLeft, Edit2, Trash2, Loader2, Save, Fingerprint, Smartphone, MapPin, CreditCard, Power, UserX, AlertCircle, Clock, Briefcase, HeartPulse, ShieldAlert, Palmtree, Mail, DollarSign, Calendar } from 'lucide-react';
import { dbSave, dbDelete, fetchCompleteCompanyData } from '../lib/supabase';

interface EmployeesProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Employees: React.FC<EmployeesProps> = ({ state, setState, notify }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentCalendarDate, setCurrentCalendarDate] = useState(new Date());
  const [showInactive, setShowInactive] = useState(false);
  const [showTimeModal, setShowTimeModal] = useState<{ emp: Employee, date: string, record?: AttendanceRecord } | null>(null);

  const initialFormState = { 
    name: '', 
    role: '', 
    defaultValue: '0', 
    cpf: '', 
    phone: '', 
    pixKey: '', 
    address: '',
    paymentModality: 'DIARIA' as 'DIARIA' | 'CLT',
    workload: '44H SEMANAIS',
    startTime: '08:00',
    breakStart: '12:00',
    breakEnd: '13:00',
    endTime: '17:00'
  };

  const [employeeForm, setEmployeeForm] = useState(initialFormState);

  const [pointForm, setPointForm] = useState({
    clockIn: '',
    breakStart: '',
    breakEnd: '',
    clockOut: '',
    status: 'present' as AttendanceRecord['status'],
    observation: ''
  });

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const handleToggleAttendance = async (empId: string, date: string) => {
    const emp = state.employees.find(e => e.id === empId);
    if (!emp) return;
    if (emp.status === 'inactive') return notify("Não é possível lançar frequência para inativos", "error");

    const existing = state.attendanceRecords.find(r => r.employeeId === empId && r.date === date);

    if (emp.paymentModality === 'CLT') {
      setPointForm({
        clockIn: existing?.clockIn || emp.startTime || '08:00',
        breakStart: existing?.breakStart || emp.breakStart || '12:00',
        breakEnd: existing?.breakEnd || emp.breakEnd || '13:00',
        clockOut: existing?.clockOut || emp.endTime || '17:00',
        status: existing?.status || 'present',
        observation: existing?.discountObservation || ''
      });
      setShowTimeModal({ emp, date, record: existing });
      return;
    }

    try {
      if (!existing) {
        await dbSave('attendance_records', {
          companyId: state.currentUser?.companyId,
          employeeId: empId,
          date,
          status: 'present',
          value: emp.defaultValue,
          paymentStatus: 'pendente'
        });
      } else if (existing.status === 'present') {
        await dbSave('attendance_records', { ...existing, status: 'partial', value: emp.defaultValue / 2 });
      } else if (existing.status === 'partial') {
        await dbSave('attendance_records', { ...existing, status: 'absent', value: 0 });
      } else if (existing.status === 'absent') {
        await dbSave('attendance_records', { ...existing, status: 'atestado', value: 0 });
      } else if (existing.status === 'atestado') {
        await dbSave('attendance_records', { ...existing, status: 'justified', value: 0 });
      } else {
        await dbDelete('attendance_records', existing.id);
      }
      await refreshData();
    } catch (e) { notify("Erro ao sincronizar presença", "error"); }
  };

  const handleSavePoint = async () => {
    if (!showTimeModal) return;
    const { emp, date, record } = showTimeModal;

    setIsLoading(true);
    try {
      await dbSave('attendance_records', {
        id: record?.id || undefined,
        companyId: state.currentUser?.companyId,
        employeeId: emp.id,
        date,
        status: pointForm.status,
        value: (pointForm.status === 'present' || pointForm.status === 'partial') ? emp.defaultValue : 0,
        paymentStatus: record?.paymentStatus || 'pendente',
        clockIn: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.clockIn : null,
        breakStart: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.breakStart : null,
        breakEnd: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.breakEnd : null,
        clockOut: (pointForm.status === 'present' || pointForm.status === 'partial') ? pointForm.clockOut : null,
        discountObservation: pointForm.observation
      });
      await refreshData();
      setShowTimeModal(null);
      notify("Registro atualizado");
    } catch (e) { notify("Erro ao salvar registro", "error"); } finally { setIsLoading(false); }
  };

  const handleToggleStatus = async (emp: Employee) => {
    setIsLoading(true);
    try {
      const newStatus = emp.status === 'active' ? 'inactive' : 'active';
      await dbSave('employees', { id: emp.id, status: newStatus });
      await refreshData();
      notify(`Colaborador ${newStatus === 'active' ? 'Reativado' : 'Inativado'}`);
    } catch (e) { notify("Falha ao atualizar status", "error"); } finally { setIsLoading(false); }
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!employeeForm.name) return notify("Nome completo é obrigatório", "error");

    setIsLoading(true);
    try {
      const finalValue = parseFloat(employeeForm.defaultValue) || 0;

      await dbSave('employees', {
        id: editingId || undefined,
        companyId: state.currentUser?.companyId,
        name: employeeForm.name.toUpperCase(),
        role: (employeeForm.role || 'AJUDANTE GERAL').toUpperCase(),
        defaultValue: finalValue,
        cpf: employeeForm.cpf,
        phone: employeeForm.phone,
        pixKey: employeeForm.pixKey,
        address: employeeForm.address.toUpperCase(),
        status: editingId ? (state.employees.find(e => e.id === editingId)?.status || 'active') : 'active',
        paymentModality: employeeForm.paymentModality,
        workload: employeeForm.workload.toUpperCase(),
        startTime: employeeForm.startTime,
        breakStart: employeeForm.breakStart,
        breakEnd: employeeForm.breakEnd,
        endTime: employeeForm.endTime
      });
      await refreshData();
      setShowForm(false);
      setEditingId(null);
      setEmployeeForm(initialFormState);
      notify(editingId ? "Cadastro atualizado" : "Novo colaborador integrado");
    } catch (e: any) { notify("Falha na sincronização", "error"); } finally { setIsLoading(false); }
  };

  const handleEdit = (emp: Employee) => {
    setEditingId(emp.id);
    setEmployeeForm({
      name: emp.name,
      role: emp.role,
      defaultValue: String(emp.defaultValue || 0),
      cpf: emp.cpf || '',
      phone: emp.phone || '',
      pixKey: emp.pixKey || '',
      address: emp.address || '',
      paymentModality: emp.paymentModality || 'DIARIA',
      workload: emp.workload || '44H SEMANAIS',
      startTime: emp.startTime || '08:00',
      breakStart: emp.breakStart || '12:00',
      breakEnd: emp.breakEnd || '13:00',
      endTime: emp.endTime || '17:00'
    });
    setShowForm(true);
  };

  const daysInMonth = useMemo(() => new Date(currentCalendarDate.getFullYear(), currentCalendarDate.getMonth() + 1, 0).getDate(), [currentCalendarDate]);
  const calendarDays = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const filteredEmployees = state.employees.filter(e => showInactive || e.status === 'active');

  const getAttendanceLabel = (att: AttendanceRecord | undefined, emp: Employee) => {
    if (!att) return '-';
    if (emp.paymentModality === 'CLT') {
      switch(att.status) {
        case 'present': return att.clockIn || 'OK';
        case 'atestado': return 'AT';
        case 'justified': return 'FJ';
        case 'vacation': return 'FE';
        case 'absent': return 'F';
        case 'partial': return 'P';
        default: return '-';
      }
    } else {
      switch(att.status) {
        case 'present': return 'P';
        case 'partial': return 'H';
        case 'absent': return 'F';
        case 'atestado': return 'AT';
        case 'justified': return 'FJ';
        default: return '-';
      }
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">Equipe & Frequência</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Pessoal e Presença</p>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <button onClick={() => setShowInactive(!showInactive)} className="flex-1 md:flex-none px-4 py-2.5 bg-white border border-slate-200 rounded-xl font-black text-[9px] uppercase transition-all shadow-sm">
             {showInactive ? 'Filtrar Ativos' : 'Exibir Todos'}
          </button>
          <button onClick={() => { setEditingId(null); setEmployeeForm(initialFormState); setShowForm(true); }} className="flex-1 md:flex-none bg-slate-900 text-white px-5 py-3 rounded-xl font-black text-[9px] uppercase shadow-lg hover:bg-emerald-600 transition-all flex items-center justify-center gap-2">
             <UserPlus size={16}/> Novo Cadastro
          </button>
        </div>
      </header>

      <div className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-300">
        <div className="p-4 md:p-6 border-b bg-slate-50 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <button onClick={() => setCurrentCalendarDate(new Date(currentCalendarDate.setMonth(currentCalendarDate.getMonth() - 1)))} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200"><ChevronLeft size={18} /></button>
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-900">{currentCalendarDate.toLocaleString('pt-BR', { month: 'long', year: 'numeric' }).toUpperCase()}</h3>
            <button onClick={() => setCurrentCalendarDate(new Date(currentCalendarDate.setMonth(currentCalendarDate.getMonth() + 1)))} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200"><ChevronRight size={18} /></button>
          </div>
          <div className="hidden sm:flex items-center gap-4 text-slate-400 font-black text-[8px] uppercase tracking-widest">
             Legenda: <span className="text-emerald-500">P/OK=Presença</span> • <span className="text-rose-500">F=Falta</span> • <span className="text-purple-500">AT=Atestado</span> • <span className="text-blue-500">FJ=Justificada</span> • <span className="text-amber-500">FE=Férias</span>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full min-w-[800px] border-collapse">
            <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase border-b">
              <tr>
                <th className="sticky left-0 z-20 bg-slate-50 p-4 text-left border-r shadow-[4px_0_10px_-4px_rgba(0,0,0,0.1)] min-w-[200px]">Colaborador</th>
                {calendarDays.map(day => <th key={day} className="p-2 text-center border-r min-w-[34px]">{day}</th>)}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map(emp => (
                <tr key={emp.id} className={`hover:bg-slate-50/50 transition-colors group ${emp.status === 'inactive' ? 'opacity-50' : ''}`}>
                  <td className="sticky left-0 z-10 bg-white p-4 border-r shadow-[4px_0_10px_-4px_rgba(0,0,0,0.1)]">
                    <div className="flex justify-between items-center gap-2">
                      <div className="min-w-0">
                        <p className={`text-[10px] font-black uppercase truncate flex items-center gap-1 ${emp.status === 'inactive' ? 'text-slate-400 line-through' : 'text-slate-800'}`}>
                          {emp.paymentModality === 'CLT' && <Clock size={10} className="text-blue-500" />}
                          {emp.name}
                        </p>
                        <p className="text-[8px] text-slate-400 font-bold uppercase">{emp.role} • {emp.paymentModality}</p>
                      </div>
                      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => handleEdit(emp)} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={12}/></button>
                        <button onClick={() => handleToggleStatus(emp)} className={`p-1.5 rounded-lg ${emp.status === 'active' ? 'text-rose-400 hover:bg-rose-50' : 'text-emerald-500 hover:bg-emerald-50'}`}><Power size={12}/></button>
                      </div>
                    </div>
                  </td>
                  {calendarDays.map(day => {
                    const dateStr = `${currentCalendarDate.getFullYear()}-${String(currentCalendarDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const att = state.attendanceRecords.find(r => r.employeeId === emp.id && r.date === dateStr);
                    const isToday = dateStr === new Date().toISOString().split('T')[0];

                    let bgColor = 'text-slate-200 hover:bg-slate-100';
                    if (att) {
                        switch(att.status) {
                          case 'present': bgColor = emp.paymentModality === 'CLT' ? 'bg-blue-600 text-white' : 'bg-emerald-500 text-white'; break;
                          case 'absent': bgColor = 'bg-rose-500 text-white'; break;
                          case 'partial': bgColor = 'bg-amber-500 text-white'; break;
                          case 'atestado': bgColor = 'bg-purple-600 text-white'; break;
                          case 'justified': bgColor = 'bg-sky-500 text-white'; break;
                          case 'vacation': bgColor = 'bg-amber-400 text-white'; break;
                        }
                    } else if (isToday) {
                        bgColor = 'bg-slate-100 border-x-2 border-slate-900';
                    }

                    return (
                      <td 
                        key={day} 
                        onClick={() => handleToggleAttendance(emp.id, dateStr)}
                        className={`p-0 border-r h-12 text-center text-[8px] font-black transition-all cursor-pointer ${bgColor}`}
                      >
                        {getAttendanceLabel(att, emp)}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
           <form onSubmit={handleSaveEmployee} className="bg-white rounded-[40px] w-full max-w-2xl p-8 md:p-10 space-y-6 shadow-2xl overflow-y-auto max-h-[95vh] border border-slate-100 animate-in zoom-in-95">
              <div className="flex justify-between items-center border-b pb-6">
                 <div>
                    <h3 className="text-sm font-black uppercase text-slate-900">{editingId ? 'Editar Perfil Operacional' : 'Novo Cadastro Operacional'}</h3>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Sincronização Cloud Fera Service</p>
                 </div>
                 <button type="button" onClick={() => setShowForm(false)} className="text-slate-300 hover:text-slate-900 p-2"><X size={24}/></button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2 p-6 bg-slate-50 rounded-[32px] border border-slate-100 space-y-4">
                  <div className="flex gap-2 p-1 bg-slate-200 rounded-2xl">
                    <button type="button" onClick={() => setEmployeeForm({...employeeForm, paymentModality: 'DIARIA'})} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${employeeForm.paymentModality === 'DIARIA' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-500'}`}>DIARISTA / AUTÔNOMO</button>
                    <button type="button" onClick={() => setEmployeeForm({...employeeForm, paymentModality: 'CLT'})} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${employeeForm.paymentModality === 'CLT' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>REGIME CLT (MENSALISTA)</button>
                  </div>
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                   <input required className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black uppercase outline-none focus:bg-white focus:border-slate-900" placeholder="EX: JOÃO DA SILVA" value={employeeForm.name} onChange={e => setEmployeeForm({...employeeForm, name: e.target.value})} />
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Cargo / Função</label>
                   <select className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black uppercase outline-none" value={employeeForm.role} onChange={e => setEmployeeForm({...employeeForm, role: e.target.value})}>
                     <option value="">SELECIONE UM CARGO...</option>
                     {state.employeeRoles.map(r => <option key={r} value={r}>{r.toUpperCase()}</option>)}
                   </select>
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">{employeeForm.paymentModality === 'CLT' ? 'Salário Base (R$)' : 'Valor da Diária (R$)'}</label>
                   <div className="relative">
                      <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16}/>
                      <input type="number" step="0.01" className="w-full bg-slate-50 border border-slate-200 pl-11 pr-4 py-4 rounded-2xl text-[11px] font-black outline-none focus:bg-white" value={employeeForm.defaultValue} onChange={e => setEmployeeForm({...employeeForm, defaultValue: e.target.value})} />
                   </div>
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">CPF</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black outline-none focus:bg-white" placeholder="000.000.000-00" value={employeeForm.cpf} onChange={e => setEmployeeForm({...employeeForm, cpf: e.target.value})} />
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Telefone / WhatsApp</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black outline-none focus:bg-white" placeholder="(00) 00000-0000" value={employeeForm.phone} onChange={e => setEmployeeForm({...employeeForm, phone: e.target.value})} />
                </div>

                <div className="space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Chave PIX (Acertos)</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black outline-none focus:bg-white" placeholder="E-MAIL, CPF OU ALEATÓRIA" value={employeeForm.pixKey} onChange={e => setEmployeeForm({...employeeForm, pixKey: e.target.value})} />
                </div>

                <div className="md:col-span-2 space-y-1">
                   <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Endereço de Residência</label>
                   <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl text-[11px] font-black uppercase outline-none focus:bg-white" placeholder="RUA, NÚMERO, BAIRRO, CIDADE" value={employeeForm.address} onChange={e => setEmployeeForm({...employeeForm, address: e.target.value})} />
                </div>

                {employeeForm.paymentModality === 'CLT' && (
                  <div className="md:col-span-2 p-6 bg-blue-50 rounded-[32px] border border-blue-100 space-y-4">
                     <h4 className="text-[10px] font-black text-blue-600 uppercase flex items-center gap-2"><Clock size={16}/> Configuração de Jornada de Trabalho</h4>
                     <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-blue-400 uppercase">ENTRADA</label>
                           <input type="time" className="w-full bg-white border border-blue-200 p-3 rounded-xl text-[10px] font-black" value={employeeForm.startTime} onChange={e => setEmployeeForm({...employeeForm, startTime: e.target.value})}/>
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-blue-400 uppercase">S. ALMOÇO</label>
                           <input type="time" className="w-full bg-white border border-blue-200 p-3 rounded-xl text-[10px] font-black" value={employeeForm.breakStart} onChange={e => setEmployeeForm({...employeeForm, breakStart: e.target.value})}/>
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-blue-400 uppercase">R. ALMOÇO</label>
                           <input type="time" className="w-full bg-white border border-blue-200 p-3 rounded-xl text-[10px] font-black" value={employeeForm.breakEnd} onChange={e => setEmployeeForm({...employeeForm, breakEnd: e.target.value})}/>
                        </div>
                        <div className="space-y-1">
                           <label className="text-[8px] font-black text-blue-400 uppercase">SAÍDA FINAL</label>
                           <input type="time" className="w-full bg-white border border-blue-200 p-3 rounded-xl text-[10px] font-black" value={employeeForm.endTime} onChange={e => setEmployeeForm({...employeeForm, endTime: e.target.value})}/>
                        </div>
                     </div>
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-blue-400 uppercase">CARGA HORÁRIA TOTAL</label>
                        <input className="w-full bg-white border border-blue-200 p-3 rounded-xl text-[10px] font-black uppercase" placeholder="EX: 44H SEMANAIS" value={employeeForm.workload} onChange={e => setEmployeeForm({...employeeForm, workload: e.target.value})}/>
                     </div>
                  </div>
                )}
              </div>

              <div className="pt-4">
                <button disabled={isLoading} type="submit" className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black uppercase text-[11px] tracking-[0.2em] shadow-xl transition-all hover:bg-emerald-600 active:scale-95 flex items-center justify-center gap-3">
                   {isLoading ? <Loader2 className="animate-spin" size={18} /> : <><Save size={18} /> SALVAR CADASTRO</>}
                </button>
              </div>
           </form>
        </div>
      )}

      {showTimeModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
           <div className="bg-white rounded-[40px] w-full max-w-md p-10 space-y-6 shadow-2xl border border-slate-100 animate-in zoom-in-95">
              <div className="flex justify-between items-center border-b pb-4">
                 <div>
                    <h3 className="text-sm font-black uppercase text-slate-900">Registro de Ponto: {showTimeModal.emp.name.split(' ')[0]}</h3>
                    <p className="text-[9px] font-bold text-slate-400 uppercase mt-1">{showTimeModal.date.split('-').reverse().join('/')}</p>
                 </div>
                 <button onClick={() => setShowTimeModal(null)} className="p-2"><X size={20}/></button>
              </div>

              <div className="space-y-4">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-[8px] font-black text-slate-400 uppercase ml-1">ENTRADA</label>
                       <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-xs" value={pointForm.clockIn} onChange={e => setPointForm({...pointForm, clockIn: e.target.value})}/>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[8px] font-black text-slate-400 uppercase ml-1">S. ALMOÇO</label>
                       <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-xs" value={pointForm.breakStart} onChange={e => setPointForm({...pointForm, breakStart: e.target.value})}/>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[8px] font-black text-slate-400 uppercase ml-1">R. ALMOÇO</label>
                       <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-xs" value={pointForm.breakEnd} onChange={e => setPointForm({...pointForm, breakEnd: e.target.value})}/>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[8px] font-black text-slate-400 uppercase ml-1">SAÍDA FINAL</label>
                       <input type="time" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-xs" value={pointForm.clockOut} onChange={e => setPointForm({...pointForm, clockOut: e.target.value})}/>
                    </div>
                 </div>

                 <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase ml-1">STATUS DO DIA</label>
                    <select className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-[10px] uppercase" value={pointForm.status} onChange={e => setPointForm({...pointForm, status: e.target.value as any})}>
                       <option value="present">PRESENÇA NORMAL (P)</option>
                       <option value="partial">HORÁRIO REDUZIDO (H)</option>
                       <option value="absent">FALTA INJUSTIFICADA (F)</option>
                       <option value="atestado">ATESTADO MÉDICO (AT)</option>
                       <option value="justified">FALTA JUSTIFICADA (FJ)</option>
                       <option value="vacation">FÉRIAS / FOLGA (FE)</option>
                    </select>
                 </div>

                 <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase ml-1">OBSERVAÇÕES / JUSTIFICATIVA</label>
                    <textarea className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl font-black text-[10px] uppercase h-20 outline-none focus:bg-white" placeholder="DESCREVA O MOTIVO DA AUSÊNCIA OU ALTERAÇÃO..." value={pointForm.observation} onChange={e => setPointForm({...pointForm, observation: e.target.value})}/>
                 </div>
              </div>

              <button onClick={handleSavePoint} disabled={isLoading} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-emerald-600 transition-all">
                 {isLoading ? <Loader2 className="animate-spin mx-auto" size={16}/> : 'CONFIRMAR REGISTRO'}
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default Employees;

import React, { useState, useMemo, useEffect } from 'react';
import { AppState, AttendanceRecord } from '../types';
import { 
  Printer, Search, Calendar, FileText, User, Hash, Smartphone, Database, TableProperties,
  Users, DollarSign, Edit2, Save, Loader2, Clock, CheckCircle2, MapPin, X
} from 'lucide-react';
import { dbSave, fetchCompleteCompanyData } from '../lib/supabase';

interface AnalyticsProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Analytics: React.FC<AnalyticsProps> = ({ state, setState, notify }) => {
  const [selectedEmployeeId, setSelectedEmployeeId] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [showPrintView, setShowPrintView] = useState(false);
  const [editingRecordId, setEditingRecordId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const [editingValue, setEditingValue] = useState('');
  const [editingDiscount, setEditingDiscount] = useState('');
  const [editingObservation, setEditingObservation] = useState('');

  const [showFinanceModal, setShowFinanceModal] = useState(false);
  const [financeTitle, setFinanceTitle] = useState('');
  const [financeCategory, setFinanceCategory] = useState('');

  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    return new Date(d.getFullYear(), d.getMonth(), 1).toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => {
    const d = new Date();
    return new Date(d.getFullYear(), d.getMonth() + 1, 0).toISOString().split('T')[0];
  });

  const formatMoney = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const formatDate = (dateStr: string) => dateStr.split('-').reverse().join('/');
  const isWithinRange = (dateStr: string) => dateStr >= startDate && dateStr <= endDate;

  const downloadCSV = (filename: string, content: string) => {
    const blob = new Blob(["\ufeff" + content], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().getTime()}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportInventory = () => {
    const headers = ["ID", "ITEM", "CATEGORIA", "QTD ATUAL", "VALOR UN", "TOTAL EM ESTOQUE"];
    const rows = state.inventory.map(i => [i.id, i.name, i.category, i.currentQty, i.unitValue, (i.currentQty * (i.unitValue || 0))]);
    const csvContent = [headers, ...rows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Estoque", csvContent);
    notify("Planilha de estoque gerada!");
  };

  const exportEmployees = () => {
    const headers = ["ID", "NOME", "CARGO", "STATUS", "DIARIA PADRAO", "CPF", "MODALIDADE", "CARGA HORARIA"];
    const rows = state.employees.map(e => [e.id, e.name, e.role, e.status, e.defaultValue, e.cpf || "", e.paymentModality, e.workload || ""]);
    const csvContent = [headers, ...rows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Equipe", csvContent);
    notify("Planilha de equipe gerada!");
  };

  const exportFinance = () => {
    const headers = ["DATA", "TIPO", "REFERENCIA", "CATEGORIA", "VALOR"];
    const rowsIn = state.cashIn.map(i => [i.date, "ENTRADA", i.reference, i.category, i.value]);
    const rowsOut = state.cashOut.map(o => [o.date, "SAIDA", o.reference, o.category, o.value]);
    const allRows = [...rowsIn, ...rowsOut].sort((a, b) => String(a[0]).localeCompare(String(b[0])));
    const csvContent = [headers, ...allRows].map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Financeiro", csvContent);
    notify("Fluxo de caixa exportado!");
  };

  const exportProduction = () => {
    const headers = ["DATA", "O.S.", "TIPO SERVICO", "QUANTIDADE", "VALOR UN", "VALOR TOTAL"];
    const rows: any[] = [];
    state.areas.forEach(area => {
      (area.services || []).forEach(s => {
        rows.push([s.serviceDate, area.name, s.type, s.areaM2, s.unitValue, s.totalValue]);
      });
    });
    const csvContent = [headers, ...rows].sort((a, b) => String(a[0]).localeCompare(String(b[0]))).map(e => e.join(";")).join("\n");
    downloadCSV("Relatorio_Producao", csvContent);
    notify("Dados de produção exportados!");
  };

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const filteredEmployees = state.employees.filter(e => e.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const selectedEmployee = state.employees.find(e => e.id === selectedEmployeeId);

  const attendanceHistory = useMemo(() => {
    return state.attendanceRecords
      .filter(r => r.employeeId === selectedEmployeeId && isWithinRange(r.date))
      .sort((a, b) => a.date.localeCompare(b.date));
  }, [state.attendanceRecords, selectedEmployeeId, startDate, endDate]);

  const totalBaseValue = attendanceHistory.reduce((acc, r) => acc + r.value, 0);
  const totalDiscounts = attendanceHistory.reduce((acc, r) => acc + (r.discountValue || 0), 0);
  const totalToPay = totalBaseValue - totalDiscounts;

  const handlePrint = () => {
    setShowPrintView(true);
    // Timeout para garantir que o DOM renderizou o conteúdo da impressão
    setTimeout(() => {
      window.print();
      if (selectedEmployee?.paymentModality !== 'CLT' && totalToPay > 0) {
        setFinanceTitle(`ACERTO: ${selectedEmployee?.name} - ${formatDate(startDate)} a ${formatDate(endDate)}`);
        setFinanceCategory('Salários');
        setShowFinanceModal(true);
      }
    }, 1000);
  };

  const handleSaveValue = async (record: AttendanceRecord) => {
    const newVal = parseFloat(editingValue.replace(',', '.'));
    const newDiscount = parseFloat(editingDiscount.replace(',', '.'));

    setIsLoading(true);
    try {
      await dbSave('attendance_records', { 
        ...record, 
        value: isNaN(newVal) ? record.value : newVal,
        discountValue: isNaN(newDiscount) ? 0 : newDiscount,
        discountObservation: editingObservation
      });
      await refreshData();
      setEditingRecordId(null);
      notify("Alterações salvas!");
    } catch (e) { notify("Erro ao salvar", "error"); } finally { setIsLoading(false); }
  };

  const togglePaymentStatus = async (record: AttendanceRecord) => {
    setIsLoading(true);
    try {
      const newStatus = record.paymentStatus === 'pago' ? 'pendente' : 'pago';
      await dbSave('attendance_records', { ...record, paymentStatus: newStatus });
      await refreshData();
      notify(`Status alterado para ${newStatus.toUpperCase()}`);
    } catch (e) { notify("Erro ao alterar status", "error"); } finally { setIsLoading(false); }
  };

  const handleCreateFinanceExit = async () => {
    if (!selectedEmployee) return;

    setIsLoading(true);
    try {
      await dbSave('cash_flow', {
        companyId: state.currentUser?.companyId,
        type: 'out',
        value: totalToPay,
        date: new Date().toISOString().split('T')[0],
        reference: financeTitle || `ACERTO: ${selectedEmployee.name}`,
        category: financeCategory || 'Salários'
      });

      const updates = attendanceHistory.map(record => 
        dbSave('attendance_records', {
          ...record,
          paymentStatus: 'pago'
        })
      );

      await Promise.all(updates);
      await refreshData();
      setShowFinanceModal(false);
      notify("Saída financeira registrada e registros quitados!");
    } catch (e: any) {
      notify("Falha ao registrar acerto financeiro.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const getStatusLabel = (status: AttendanceRecord['status']) => {
    switch(status) {
      case 'present': return 'PRESENÇA INTEGRAL';
      case 'partial': return 'HORÁRIO PARCIAL';
      case 'absent': return 'FALTA INJUSTIFICADA';
      case 'atestado': return 'ATESTADO MÉDICO';
      case 'justified': return 'FALTA JUSTIFICADA';
      case 'vacation': return 'FÉRIAS / FOLGA';
      default: return 'SEM REGISTRO';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 print:hidden">
        <div>
          <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase">Relatórios de Acerto</h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest opacity-70">Geração de Fichas Financeiras Individuais</p>
        </div>
        <div className="flex items-center gap-2 bg-white border border-slate-200 p-2 rounded-xl shadow-sm">
          <Calendar size={14} className="text-slate-400" />
          <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-[10px] font-black uppercase bg-transparent outline-none" />
          <span className="text-slate-300">|</span>
          <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-[10px] font-black uppercase bg-transparent outline-none" />
        </div>
      </header>

      <section className="bg-slate-900 text-white rounded-[32px] p-6 shadow-2xl relative overflow-hidden print:hidden border border-white/5">
         <div className="relative z-10">
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-3 mb-5 opacity-70">
              <Database size={16} className="text-blue-400"/> Central de Dados e Exportação (CSV)
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
               <button onClick={exportInventory} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center gap-4 transition-all hover:bg-blue-600 group">
                  <TableProperties size={18}/>
                  <div className="text-left"><span className="text-[10px] font-black uppercase block">Estoque</span><span className="text-[8px] font-bold opacity-40 uppercase">Exportar Materiais</span></div>
               </button>
               <button onClick={exportEmployees} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center gap-4 transition-all hover:bg-emerald-600 group">
                  <Users size={18}/><div className="text-left"><span className="text-[10px] font-black uppercase block">Equipe</span><span className="text-[8px] font-bold opacity-40 uppercase">Lista Colaboradores</span></div>
               </button>
               <button onClick={exportFinance} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center gap-4 transition-all hover:bg-orange-600 group">
                  <DollarSign size={18}/><div className="text-left"><span className="text-[10px] font-black uppercase block">Fluxo Caixa</span><span className="text-[8px] font-bold opacity-40 uppercase">Entradas e Saídas</span></div>
               </button>
               <button onClick={exportProduction} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center gap-4 transition-all hover:bg-indigo-600 group">
                  <MapPin size={18}/><div className="text-left"><span className="text-[10px] font-black uppercase block">Produção</span><span className="text-[8px] font-bold opacity-40 uppercase">Metragens Campo</span></div>
               </button>
            </div>
         </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 print:hidden">
        <div className="bg-white border border-slate-200 rounded-[32px] overflow-hidden shadow-sm lg:col-span-1 h-[calc(100vh-320px)] flex flex-col transition-all">
          <div className="p-6 border-b border-slate-100 bg-slate-50/30">
             <div className="relative">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input className="w-full bg-white border-2 border-slate-100 pl-14 pr-4 py-5 rounded-[24px] text-[12px] font-black uppercase outline-none focus:border-slate-900 focus:bg-white transition-all shadow-sm" placeholder="BUSCAR NOME..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
             </div>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
             {filteredEmployees.map(emp => (
               <button key={emp.id} onClick={() => setSelectedEmployeeId(emp.id)} className={`w-full flex items-center p-7 rounded-[28px] text-left transition-all border-l-[6px] ${selectedEmployeeId === emp.id ? 'bg-slate-900 text-white shadow-2xl border-emerald-500 translate-x-1 scale-[1.02]' : 'hover:bg-slate-50 text-slate-600 border-transparent'}`}>
                  <div className="min-w-0">
                     <p className="text-sm font-black uppercase truncate tracking-tight flex items-center gap-2">{emp.paymentModality === 'CLT' && <Clock size={12} className="text-blue-500" />}{emp.name}</p>
                     <p className={`text-[10px] font-bold uppercase tracking-[0.15em] mt-1 ${selectedEmployeeId === emp.id ? 'text-emerald-400' : 'text-slate-400'}`}>{emp.role} • {emp.paymentModality}</p>
                  </div>
               </button>
             ))}
          </div>
        </div>

        <div className="lg:col-span-3">
           {selectedEmployee ? (
             <div className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-right-4 duration-300 h-full flex flex-col">
                <div className="p-8 bg-slate-900 text-white space-y-6">
                   <div className="flex flex-col md:flex-row justify-between gap-6">
                      <div className="flex-1 space-y-4">
                         <div className="flex items-center gap-3">
                            <div className="p-3 bg-white/10 rounded-2xl border border-white/5"><User size={20} className="text-emerald-400" /></div>
                            <div><h4 className="text-xl font-black uppercase leading-tight tracking-tight">{selectedEmployee.name}</h4><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{selectedEmployee.role} • {selectedEmployee.paymentModality}</p></div>
                         </div>
                         <div className="grid grid-cols-2 gap-4">
                            <div className="text-[10px] text-slate-400 font-bold uppercase"><Hash size={12}/> CPF: <span className="text-white ml-2">{selectedEmployee.cpf || '--'}</span></div>
                            <div className="text-[10px] text-slate-400 font-bold uppercase"><Smartphone size={12}/> CONTATO: <span className="text-white ml-2">{selectedEmployee.phone || '--'}</span></div>
                            {selectedEmployee.paymentModality === 'CLT' && (<div className="text-[10px] text-blue-400 font-black uppercase col-span-2 flex items-center gap-2"><Clock size={12}/> JORNADA: {selectedEmployee.workload} ({selectedEmployee.startTime} às {selectedEmployee.endTime})</div>)}
                         </div>
                      </div>
                      <div className="md:w-64 bg-white/5 p-6 rounded-[32px] border border-white/10 flex flex-col justify-center text-center">
                         {selectedEmployee.paymentModality !== 'CLT' && (<><p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1">Total Líquido</p><h2 className="text-3xl font-black text-emerald-400 tracking-tighter">{formatMoney(totalToPay)}</h2></>)}
                         <button onClick={handlePrint} className="mt-4 w-full bg-white text-slate-900 py-3.5 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-400 transition-all shadow-xl active:scale-95"><Printer size={16} /> GERAR PDF / IMPRIMIR</button>
                      </div>
                   </div>
                </div>
                <div className="flex-1 overflow-y-auto scrollbar-hide">
                   <table className="w-full text-left">
                      <thead className="bg-slate-50 text-[9px] uppercase text-slate-400 font-black border-b border-slate-100 sticky top-0 z-10">
                         <tr>
                           <th className="px-8 py-4">Data</th>
                           <th className="px-8 py-4 text-center">Registro</th>
                           {selectedEmployee.paymentModality === 'CLT' ? (
                             <th className="px-8 py-4 text-center">Horários (E-SA-RA-SF)</th>
                           ) : (
                             <><th className="px-8 py-4 text-right">Base</th><th className="px-8 py-4 text-right">Desc.</th></>
                           )}
                           <th className="px-8 py-4 text-left">Observação</th>
                           {selectedEmployee.paymentModality !== 'CLT' && (<th className="px-8 py-4 text-center">Pagamento</th>)}
                           <th className="px-8 py-4 text-right">Ação</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50 text-[11px] font-black uppercase text-slate-700">
                         {attendanceHistory.map(h => {
                             const isEditing = editingRecordId === h.id;
                             return (
                               <tr key={h.id} className="hover:bg-slate-50 transition-colors">
                                  <td className="px-8 py-3 text-slate-500">{formatDate(h.date)}</td>
                                  <td className="px-8 py-3 text-center">
                                     <span className={`px-3 py-1 rounded-lg text-[8px] font-black ${
                                         h.status === 'present' ? 'bg-emerald-50 text-emerald-600' : 
                                         h.status === 'absent' ? 'bg-rose-50 text-rose-600' :
                                         h.status === 'atestado' ? 'bg-purple-50 text-purple-600' :
                                         'bg-sky-50 text-sky-600'
                                     }`}>
                                        {getStatusLabel(h.status).replace('PRESENÇA INTEGRAL', 'INTEGRAL').replace('HORÁRIO PARCIAL', 'PARCIAL')}
                                     </span>
                                  </td>
                                  {selectedEmployee.paymentModality === 'CLT' ? (
                                    <td className="px-8 py-3 text-center font-bold text-slate-400 text-[9px]">
                                      {h.clockIn ? `${h.clockIn} | ${h.breakStart || '--'} | ${h.breakEnd || '--'} | ${h.clockOut || '--'}` : '--'}
                                    </td>
                                  ) : (
                                    <><td className="px-8 py-3 text-right">{isEditing ? (<input className="w-20 bg-white border border-slate-200 p-2 rounded-lg text-[10px] font-black text-right" value={editingValue} onChange={e => setEditingValue(e.target.value)} />) : (<span className="font-bold">{formatMoney(h.value)}</span>)}</td><td className="px-8 py-3 text-right text-rose-500">{isEditing ? (<input className="w-20 bg-white border border-slate-200 p-2 rounded-lg text-[10px] font-black text-right" value={editingDiscount} onChange={e => setEditingDiscount(e.target.value)} />) : (`- ${formatMoney(h.discountValue || 0)}`)}</td></>
                                  )}
                                  <td className="px-8 py-3 text-left">{isEditing ? (<input className="w-full min-w-[150px] bg-white border border-slate-200 p-2 rounded-lg text-[10px] font-black uppercase" placeholder="OBSERVAÇÃO..." value={editingObservation} onChange={e => setEditingObservation(e.target.value)} />) : (<span className="text-[9px] text-slate-400 italic lowercase">{h.discountObservation || '--'}</span>)}</td>
                                  {selectedEmployee.paymentModality !== 'CLT' && (<td className="px-8 py-3 text-center"><button onClick={() => togglePaymentStatus(h)} className={`px-3 py-1.5 rounded-xl text-[8px] font-black transition-all ${h.paymentStatus === 'pago' ? 'bg-emerald-600 text-white' : 'bg-amber-100 text-amber-600'}`}>{h.paymentStatus === 'pago' ? 'PAGO' : 'PENDENTE'}</button></td>)}
                                  <td className="px-8 py-3 text-right">{isEditing ? (<button onClick={() => handleSaveValue(h)} className="p-1.5 text-emerald-600 bg-emerald-50 rounded-lg"><Save size={14}/></button>) : (<button onClick={() => { setEditingRecordId(h.id); setEditingValue(String(h.value)); setEditingDiscount(String(h.discountValue || 0)); setEditingObservation(h.discountObservation || ''); }} className="p-1.5 text-slate-300 hover:text-blue-500 transition-colors"><Edit2 size={12}/></button>)}</td>
                               </tr>
                             );
                           })
                         }
                      </tbody>
                   </table>
                </div>
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center bg-slate-50 border-2 border-dashed border-slate-200 rounded-[40px] p-20 text-center opacity-40"><FileText size={48} className="text-slate-300 mb-6" /><h3 className="text-sm font-black text-slate-400 uppercase tracking-[0.3em]">Relatório Individual</h3><p className="text-[10px] font-bold text-slate-400 uppercase mt-2">Selecione um colaborador para gerar o acerto.</p></div>
           )}
        </div>
      </div>

      {showPrintView && selectedEmployee && (
        <div className="fixed inset-0 z-[1000] bg-white text-slate-900 font-sans print-view-container overflow-y-auto">
           <style>{`
             @media print { 
               @page { margin: 0; size: A4 portrait; }
               body * { visibility: hidden; }
               .print-view-container, .print-view-container * { visibility: visible; }
               .print-view-container { 
                  position: absolute !important; 
                  left: 0 !important; 
                  top: 0 !important; 
                  width: 100% !important; 
                  margin: 0 !important; 
                  padding: 0 !important; 
                  background: white !important;
               }
               .no-print { display: none !important; }
               .sheet { 
                  box-shadow: none !important; 
                  margin: 0 !important; 
                  width: 100% !important; 
                  padding: 1cm !important;
                  border: none !important;
               }
               * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
             }
             @media screen {
                .print-view-container { display: flex; align-items: flex-start; justify-content: center; padding: 40px; background: rgba(0,0,0,0.8); backdrop-blur: 10px; }
                .sheet { background: white; margin: 0 auto; padding: 1.5cm; width: 210mm; min-height: 297mm; box-shadow: 0 0 50px rgba(0,0,0,0.5); position: relative; border-radius: 4px; }
             }
           `}</style>

           <div className="sheet">
